import React, { useState, useRef, useEffect } from 'react';
import { Film, Download, RotateCcw, Settings2, MonitorPlay, Globe, Square, RefreshCw, Play, Pause, RotateCw, Volume2, VolumeX, Maximize2, Minimize2, Gauge } from 'lucide-react';
import { Chapter, FileContext } from '../types';
import { generateSummaryVideo, hasValidKeyForVeo, requestVeoKey } from '../services/gemini';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
}

const STYLES = [
  'Cinematic', 'Anime', 'Photorealistic', 'Cartoon', 'Cyberpunk', 
  'Vaporwave', 'Noir', 'Documentary', 'Surreal'
];

const LANGUAGES = [
  'Original', 'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const RESOLUTIONS: ('720p' | '1080p' | '4K')[] = ['720p', '1080p', '4K'];
const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

export const VideoSummary: React.FC<Props> = ({ chapter, fileContext }) => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [status, setStatus] = useState<string>("");
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedStyle, setSelectedStyle] = useState('Cinematic');
  const [selectedLanguage, setSelectedLanguage] = useState('Original');
  const [selectedResolution, setSelectedResolution] = useState<'720p' | '1080p' | '4K'>('720p');

  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isMuted, setIsMuted] = useState(false);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [playbackProgress, setPlaybackProgress] = useState(0);
  const [controlsVisible, setControlsVisible] = useState(true);

  const abortRef = useRef<boolean>(false);
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const containerRef = useRef<HTMLDivElement | null>(null);
  const controlsTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    return () => {
      if (videoUrl) URL.revokeObjectURL(videoUrl);
    };
  }, [videoUrl]);

  const handleToggleGeneration = async () => {
    if (isGenerating) {
        abortRef.current = true;
        setIsGenerating(false);
        setStatus("");
        return;
    }
    setError(null);
    setIsGenerating(true);
    abortRef.current = false;
    setStatus("Authenticating & Generating...");
    try {
      const hasKey = await hasValidKeyForVeo();
      if (!hasKey) {
        setStatus("Waiting for Access Key...");
        await requestVeoKey();
      }
      if (abortRef.current) return;

      const targetLang = selectedLanguage === 'Original' ? 'the source language of the document' : selectedLanguage;
      const url = await generateSummaryVideo(
        fileContext, 
        chapter, 
        setStatus, 
        selectedStyle, 
        targetLang,
        selectedResolution === '4K' ? '1080p' : selectedResolution as any
      );

      if (!abortRef.current) {
        if (videoUrl) URL.revokeObjectURL(videoUrl);
        setVideoUrl(url);
        setIsPlaying(false);
      }
    } catch (e: any) {
      if (!abortRef.current) {
        console.error(e);
        let msg = "Generation failed.";
        if (e.message?.includes("Requested entity was not found")) {
            msg = "Key Invalid. Paid project key required.";
            await requestVeoKey();
        } else if (e.message) msg = e.message;
        setError(msg);
      }
    } finally {
      if (!abortRef.current) {
        setIsGenerating(false);
        setStatus("");
      }
    }
  };

  const togglePlay = async (e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!videoRef.current || !videoUrl) return;

    try {
      if (isPlaying) {
        videoRef.current.pause();
        setIsPlaying(false);
      } else {
        const playPromise = videoRef.current.play();
        if (playPromise !== undefined) {
          await playPromise;
          setIsPlaying(true);
        }
      }
    } catch (err) {
      console.warn("Playback interrupted or failed:", err);
      setIsPlaying(false);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    if (videoRef.current && duration) {
       videoRef.current.currentTime = (val / 100) * duration;
    }
  };

  const toggleMute = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (videoRef.current) {
        videoRef.current.muted = !isMuted;
        setIsMuted(!isMuted);
    }
  };

  const toggleFullScreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
        containerRef.current.requestFullscreen().catch(err => {
            console.error(`Error attempting to enable full-screen mode: ${err.message}`);
        });
    } else {
        document.exitFullscreen();
    }
  };

  const resetControlsTimeout = () => {
    setControlsVisible(true);
    if (controlsTimeoutRef.current) {
      window.clearTimeout(controlsTimeoutRef.current);
    }
    if (isPlaying) {
      controlsTimeoutRef.current = window.setTimeout(() => {
        setControlsVisible(false);
      }, 3000);
    }
  };

  useEffect(() => {
    const handleFsChange = () => {
      const isFs = !!document.fullscreenElement;
      setIsFullScreen(isFs);
      if (!isFs) setControlsVisible(true);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const formatTime = (seconds: number): string => {
    if (!seconds || isNaN(seconds)) return "00:00";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left overflow-hidden">
       {/* Header */}
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 animate-fade-in shadow-[0_0_15px_rgba(0,243,255,0.05)] flex-nowrap gap-2 z-10">
          <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
             <Film size={18} className="text-[#00f3ff]" />
             <span>Cine_Render</span>
          </div>
          {/* Changed from gap-2 or gap-x to gap-4 for 16px separation */}
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                  <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                  <select value={selectedStyle} onChange={(e) => setSelectedStyle(e.target.value)} disabled={isGenerating} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[100px] bg-[#050505]">
                    {STYLES.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                  <div className="w-[1px] h-4 bg-zinc-700"></div>
                   <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                   <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} disabled={isGenerating} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[100px] bg-[#050505]">
                      {LANGUAGES.map(l => <option key={l} value={l}>{l}</option>)}
                   </select>
                   <div className="w-[1px] h-4 bg-zinc-700"></div>
                   <div className="p-1.5 text-zinc-500"><MonitorPlay size={16} /></div>
                   <select value={selectedResolution} onChange={(e) => setSelectedResolution(e.target.value as any)} disabled={isGenerating} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[60px] bg-[#050505]">
                      {RESOLUTIONS.map(r => <option key={r} value={r}>{r}</option>)}
                   </select>
              </div>

              <button 
                onClick={handleToggleGeneration} 
                disabled={isGenerating && status === "Authenticating..."}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isGenerating ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {isGenerating ? <Square size={14} fill="currentColor" /> : videoUrl ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />}
                 {isGenerating ? "STOP" : videoUrl ? "REGENERATE" : "INITIATE"}
              </button>
          </div>
       </div>

       {/* Main Player Area */}
       <div 
          ref={containerRef}
          className="flex-1 bg-[#0a0a0c] border border-zinc-800 rounded-lg relative overflow-hidden flex flex-col items-center justify-center group shadow-2xl"
          onMouseMove={resetControlsTimeout}
          onClick={resetControlsTimeout}
       >
           {/* Grid Background */}
           <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.03)_1px,transparent_1px)] bg-[size:40px_40px] pointer-events-none"></div>

           {isGenerating ? (
               <div className="z-10 flex flex-col items-center gap-4">
                   <Loader text={status || "INITIALIZING_VEO_CORE..."} />
               </div>
           ) : videoUrl ? (
               <div className="w-full h-full relative bg-black flex items-center justify-center">
                   <video 
                     ref={videoRef}
                     src={videoUrl}
                     className="max-w-full max-h-full"
                     onTimeUpdate={() => {
                        if(videoRef.current) {
                            setCurrentTime(videoRef.current.currentTime);
                            setDuration(videoRef.current.duration || 0);
                            setPlaybackProgress((videoRef.current.currentTime / videoRef.current.duration) * 100);
                        }
                     }}
                     onEnded={() => setIsPlaying(false)}
                     loop={false}
                     playsInline
                     onClick={togglePlay}
                   />

                   {/* Custom Controls Overlay */}
                   <div className={`absolute bottom-0 left-0 w-full bg-gradient-to-t from-black/90 to-transparent p-4 transition-opacity duration-300 ${controlsVisible ? 'opacity-100' : 'opacity-0'}`}>
                       {/* Progress Bar */}
                       <div className="w-full h-1 bg-zinc-800 mb-4 cursor-pointer relative group/progress">
                           <div className="absolute inset-y-0 left-0 bg-[#00f3ff] shadow-[0_0_10px_#00f3ff]" style={{ width: `${playbackProgress}%` }}></div>
                           <input 
                             type="range" 
                             min="0" 
                             max="100" 
                             step="0.1"
                             value={playbackProgress}
                             onChange={handleSeek}
                             className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                           />
                       </div>

                       <div className="flex items-center justify-between">
                           <div className="flex items-center gap-4">
                               <button onClick={togglePlay} className="text-white hover:text-[#00f3ff] transition-colors">
                                   {isPlaying ? <Pause size={20} fill="currentColor" /> : <Play size={20} fill="currentColor" />}
                               </button>
                               <button onClick={toggleMute} className="text-zinc-400 hover:text-white transition-colors">
                                   {isMuted ? <VolumeX size={18} /> : <Volume2 size={18} />}
                               </button>
                               <span className="text-xs font-mono text-zinc-400">
                                   {formatTime(currentTime)} / {formatTime(duration)}
                               </span>
                           </div>

                           <div className="flex items-center gap-4">
                               {/* Speed */}
                               <div className="flex items-center gap-1 bg-black/40 rounded px-2 py-1">
                                   <Gauge size={14} className="text-zinc-500" />
                                   <select 
                                     value={playbackRate}
                                     onChange={(e) => {
                                         const rate = parseFloat(e.target.value);
                                         setPlaybackRate(rate);
                                         if(videoRef.current) videoRef.current.playbackRate = rate;
                                     }}
                                     className="bg-transparent text-[10px] font-mono text-[#00f3ff] outline-none cursor-pointer"
                                   >
                                       {SPEEDS.map(s => <option key={s} value={s}>{s}x</option>)}
                                   </select>
                               </div>

                               <a href={videoUrl} download={`summary-${chapter.id}.mp4`} className="text-zinc-400 hover:text-[#00f3ff] transition-colors" title="Download MP4">
                                   <Download size={18} />
                               </a>
                               <button onClick={toggleFullScreen} className="text-zinc-400 hover:text-white transition-colors">
                                   {isFullScreen ? <Minimize2 size={18} /> : <Maximize2 size={18} />}
                               </button>
                           </div>
                       </div>
                   </div>
               </div>
           ) : (
               <div className="flex flex-col items-center gap-4 text-zinc-700 animate-pulse">
                   <Film size={48} className="opacity-20" />
                   <div className="text-center font-mono">
                       <p className="text-sm font-bold uppercase tracking-widest">Veo_Core Standby</p>
                       <p className="text-[10px] opacity-60 mt-1">Configure parameters to initiate video synthesis</p>
                   </div>
               </div>
           )}

           {error && (
               <div className="absolute inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center z-20">
                   <div className="bg-rose-950/20 border border-rose-900/50 p-6 rounded-lg text-center max-w-md">
                       <p className="text-rose-500 font-bold font-mono mb-2 uppercase tracking-widest">Generation Error</p>
                       <p className="text-zinc-400 text-xs font-mono mb-4">{error}</p>
                       <button onClick={handleToggleGeneration} className="px-4 py-2 bg-rose-600 hover:bg-rose-500 text-white text-xs font-bold rounded-sm uppercase tracking-wider transition-all">
                           Retry Operation
                       </button>
                   </div>
               </div>
           )}
       </div>
    </div>
  );
};

