import React, { useState, useEffect, useMemo, useRef } from 'react';
import { NotebookItem, AppSettings, Chapter, MindMapNode } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, Settings2, Type, Loader2, ArrowUpDown, Network, Download, FileText, Share2, ZoomIn, ZoomOut, RefreshCw, Zap, X, Notebook as NotebookIcon, Play, Square, ChevronRight, ChevronDown, Minus, Plus, LogOut, FileDown } from 'lucide-react';
import { generateSpeech, generateMindMapStructure } from '../services/gemini';
import JSZip from 'jszip';
import { Document, Packer, Paragraph, TextRun, HeadingLevel } from 'docx';
import jsPDF from 'jspdf';
import { Loader } from './ui/Loader';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  onBatchUpdateDefinitions?: (updates: Record<string, string>) => void;
  settings: AppSettings;
  activeChapter?: Chapter | null;
  bookTitle?: string;
}

type FilterType = 'all' | 'word' | 'phrase' | 'sentence';
type SortOrder = 'newest' | 'oldest' | 'az' | 'za';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, onBatchUpdateDefinitions, settings, activeChapter, bookTitle }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('all');
  const [sortOrder, setSortOrder] = useState<SortOrder>('newest');

  // Mind Map State
  const [isMindMapMode, setIsMindMapMode] = useState(false);
  const [mindMapData, setMindMapData] = useState<MindMapNode | null>(null);
  const [isGeneratingMap, setIsGeneratingMap] = useState(false);
  const [hasInitiatedMap, setHasInitiatedMap] = useState(false);
  const [collapsedNodeIds, setCollapsedNodeIds] = useState<Set<string>>(new Set());
  const [mapZoom, setMapZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isPanning, setIsPanning] = useState(false);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const lastMousePos = useRef({ x: 0, y: 0 });
  const abortMapRef = useRef<boolean>(false);

  const filteredItems = useMemo(() => {
      let result = activeFilter === 'all' 
        ? [...items] 
        : items.filter(item => item.type === activeFilter);

      switch (sortOrder) {
          case 'newest':
              result.sort((a, b) => b.timestamp - a.timestamp);
              break;
          case 'oldest':
              result.sort((a, b) => a.timestamp - b.timestamp);
              break;
          case 'az':
              result.sort((a, b) => a.text.localeCompare(b.text));
              break;
          case 'za':
              result.sort((a, b) => b.text.localeCompare(a.text));
              break;
      }
      return result;
  }, [items, activeFilter, sortOrder]);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      if (item.comment) {
          ctx.fillStyle = '#f59e0b'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> USER_ANNOTATION:", margin, y); y += 20;
          ctx.fillStyle = '#b45309'; ctx.font = 'italic 14px "Courier New", monospace';
          const commentWords = item.comment.split(' ');
          let commentLine = '';
          for(let n = 0; n < commentWords.length; n++) {
            const testLine = commentLine + commentWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(commentLine, margin, y); commentLine = commentWords[n] + ' '; y += 18;
            } else { commentLine = testLine; }
         }
         ctx.fillText(commentLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const handleInitiateMindMap = async () => {
    if (isGeneratingMap) {
        abortMapRef.current = true;
        setIsGeneratingMap(false);
        return;
    }
    setIsGeneratingMap(true);
    setHasInitiatedMap(true);
    setMapZoom(1);
    setPan({ x: 0, y: 0 });
    setCollapsedNodeIds(new Set());
    abortMapRef.current = false;
    try {
        const title = activeChapter?.title || bookTitle || "Untitled Chapter";
        const context = activeChapter ? `Current Chapter: ${activeChapter.title}` : undefined;
        const structure = await generateMindMapStructure(filteredItems, title, context);
        if (abortMapRef.current) return;
        setMindMapData(structure);
        setIsMindMapMode(true);
    } catch (e) {
        if (!abortMapRef.current) console.error("Failed to generate mind map:", e);
    } finally {
        if (!abortMapRef.current) setIsGeneratingMap(false);
    }
  };

  const toggleNodeCollapse = (id: string, e?: React.MouseEvent) => {
      if (e) e.stopPropagation();
      setCollapsedNodeIds(prev => {
          const next = new Set(prev);
          if (next.has(id)) next.delete(id);
          else next.add(id);
          return next;
      });
  };

  // Panning Handlers
  const handleMapMouseDown = (e: React.MouseEvent) => {
    if (e.button !== 0) return; // Only left click
    setIsPanning(true);
    lastMousePos.current = { x: e.clientX, y: e.clientY };
  };

  const handleMapMouseMove = (e: React.MouseEvent) => {
    if (!isPanning) return;
    const dx = e.clientX - lastMousePos.current.x;
    const dy = e.clientY - lastMousePos.current.y;
    setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
    lastMousePos.current = { x: e.clientX, y: e.clientY };
  };

  const handleMapMouseUp = () => {
    setIsPanning(false);
  };

  // --- Export Functions ---

  const exportToDocx = async () => {
    if (!mindMapData) return;

    const childrenToParagraphs = (node: MindMapNode, level: number): Paragraph[] => {
        const paras = [
             new Paragraph({
                text: node.label,
                heading: level === 0 ? HeadingLevel.TITLE : level === 1 ? HeadingLevel.HEADING_1 : level === 2 ? HeadingLevel.HEADING_2 : undefined,
                bullet: level > 2 ? { level: 0 } : undefined,
             })
        ];
        if (node.children) {
            node.children.forEach(child => {
                paras.push(...childrenToParagraphs(child, level + 1));
            });
        }
        return paras;
    };

    const doc = new Document({
        sections: [{
            properties: {},
            children: childrenToParagraphs(mindMapData, 0),
        }],
    });

    const blob = await Packer.toBlob(doc);
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.docx`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToXmind = async () => {
    if (!mindMapData) return;

    const zip = new JSZip();
    const mapNodeToTopic = (node: MindMapNode): any => {
        const topic: any = {
            "id": node.id,
            "title": node.label,
            "structureClass": "org.xmind.ui.map.unbalanced"
        };
        if (node.children && node.children.length > 0) {
            topic["children"] = {
                "attached": node.children.map(mapNodeToTopic)
            };
        }
        return topic;
    };

    const content = [
        {
            "id": "sheet-1",
            "class": "sheet",
            "title": "Sheet 1",
            "rootTopic": mapNodeToTopic(mindMapData)
        }
    ];

    zip.file("content.json", JSON.stringify(content));
    zip.file("manifest.json", JSON.stringify({
        "file-entries": { "content.json": {}, "metadata.json": {} }
    }));
    zip.file("metadata.json", "{}");

    const blob = await zip.generateAsync({ type: "blob" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.xmind`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToPDF = () => {
      const doc = new jsPDF();
      doc.setFont("helvetica", "bold");
      doc.setFontSize(20);
      doc.text("Notebook Export", 10, 15);

      doc.setFont("helvetica", "normal");
      doc.setFontSize(10);
      doc.text(`Generated: ${new Date().toLocaleString()}`, 10, 22);

      let y = 35;
      const lineHeight = 7;

      filteredItems.forEach((item, idx) => {
          if (y > 270) { doc.addPage(); y = 20; }

          doc.setFont("helvetica", "bold");
          doc.setFontSize(11);
          const typeLabel = `[${item.type.toUpperCase()}]`;
          doc.text(typeLabel, 10, y);

          const textPreview = item.text.length > 50 ? item.text.substring(0, 50) + "..." : item.text;
          doc.text(`"${textPreview}"`, 40, y);

          y += lineHeight;

          if (item.definition) {
             doc.setFont("helvetica", "italic");
             doc.setFontSize(10);
             const defLines = doc.splitTextToSize(`Def: ${item.definition}`, 180);
             doc.text(defLines, 15, y);
             y += (defLines.length * lineHeight) + 2;
          }

          y += 5;
          doc.setDrawColor(200);
          doc.line(10, y, 200, y);
          y += 10;
      });

      doc.save(`notebook-export-${Date.now()}.pdf`);
  };

  const renderMindMapNode = (node: MindMapNode, depth: number = 0, x: number, y: number): JSX.Element => {
      // Simplified Mind Map rendering: Vertical lists with indentation for now to ensure robustness without complex d3 layout
      // For a true node-link diagram, one would use d3-hierarchy. Here we use a nested recursive layout component.
      return (
          <div key={node.id} className="flex flex-col items-center">
              <div 
                className={`
                    relative p-3 rounded-lg border-2 shadow-lg transition-all duration-300 group
                    ${node.type === 'root' ? 'bg-[#00f3ff]/20 border-[#00f3ff] text-white min-w-[150px] text-center' : ''}
                    ${node.type === 'category' ? 'bg-zinc-900 border-zinc-700 hover:border-zinc-500 text-zinc-200' : ''}
                    ${node.type === 'item' ? 'bg-[#0a0a0c] border-zinc-800 hover:border-[#ff003c] text-zinc-400 max-w-xs text-sm' : ''}
                `}
                onClick={(e) => toggleNodeCollapse(node.id, e)}
              >
                  <div className="font-bold font-mono text-sm flex items-center gap-2">
                     {node.type === 'root' && <Book size={16} />}
                     {node.type === 'category' && <Network size={14} className="text-[#00f3ff]" />}
                     {node.type === 'item' && <FileText size={12} className="text-[#ff003c]" />}
                     {node.label}
                  </div>
                  {node.children && node.children.length > 0 && (
                      <div className="absolute -bottom-3 left-1/2 -translate-x-1/2 bg-zinc-800 rounded-full p-0.5 border border-zinc-700">
                          {collapsedNodeIds.has(node.id) ? <Plus size={10} /> : <Minus size={10} />}
                      </div>
                  )}
              </div>

              {!collapsedNodeIds.has(node.id) && node.children && node.children.length > 0 && (
                  <div className="flex items-start gap-8 mt-8 border-t border-zinc-700/50 pt-8 relative">
                      {/* Connector lines logic would go here in a canvas or SVG, using simple CSS borders for tree structure */}
                      {node.children.map((child, idx) => (
                          <div key={child.id} className="relative">
                              {renderMindMapNode(child, depth + 1, 0, 0)}
                          </div>
                      ))}
                  </div>
              )}
          </div>
      );
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left overflow-hidden" style={fontStyle}>
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 animate-fade-in shadow-[0_0_15px_rgba(0,243,255,0.05)] flex-nowrap gap-2 z-10">
          <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
             <NotebookIcon size={18} className="text-[#00f3ff]" />
             <span>Mem_Log</span>
          </div>

          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                  <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                  <select value={activeFilter} onChange={(e) => setActiveFilter(e.target.value as FilterType)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[90px] bg-[#050505]">
                      <option value="all">ALL_DATA</option>
                      <option value="word">TERMS</option>
                      <option value="phrase">PHRASES</option>
                      <option value="sentence">IDEAS</option>
                  </select>
                  <div className="w-[1px] h-4 bg-zinc-700"></div>
                   <div className="p-1.5 text-zinc-500"><ArrowUpDown size={16} /></div>
                   <select value={sortOrder} onChange={(e) => setSortOrder(e.target.value as SortOrder)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[90px] bg-[#050505]">
                      <option value="newest">LATEST</option>
                      <option value="oldest">OLDEST</option>
                      <option value="az">A-Z</option>
                      <option value="za">Z-A</option>
                   </select>
              </div>

              <div className="flex items-center gap-2">
                 <button onClick={() => setIsMindMapMode(!isMindMapMode)} className={`flex items-center gap-2 px-3 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all ${isMindMapMode ? 'bg-[#00f3ff] text-black' : 'bg-zinc-900 text-zinc-400 hover:text-white'}`}>
                     <Network size={14} /> {isMindMapMode ? 'GRID_VIEW' : 'MIND_MAP'}
                 </button>

                 {isMindMapMode && mindMapData && (
                     <div className="flex items-center gap-1 bg-black/50 p-1 rounded-sm border border-zinc-800">
                         <button onClick={exportToDocx} className="p-1.5 hover:bg-zinc-800 text-zinc-400 hover:text-[#00f3ff] transition-colors" title="Export DOCX"><FileText size={14} /></button>
                         <button onClick={exportToXmind} className="p-1.5 hover:bg-zinc-800 text-zinc-400 hover:text-[#00f3ff] transition-colors" title="Export XMIND"><Share2 size={14} /></button>
                         <button onClick={exportToPDF} className="p-1.5 hover:bg-zinc-800 text-zinc-400 hover:text-[#00f3ff] transition-colors" title="Export PDF"><FileDown size={14} /></button>
                     </div>
                 )}
              </div>
          </div>
       </div>

       <div className="flex-1 min-h-0 bg-[#0a0a0c] border border-zinc-800 rounded-lg overflow-hidden relative shadow-inner">
           {isMindMapMode ? (
               <div className="w-full h-full relative overflow-hidden bg-[#050505]" ref={mapContainerRef} onMouseDown={handleMapMouseDown} onMouseMove={handleMapMouseMove} onMouseUp={handleMapMouseUp} onMouseLeave={handleMapMouseUp}>
                   {/* Mind Map Controls Overlay */}
                   <div className="absolute top-4 left-4 z-20 flex flex-col gap-2">
                       <div className="bg-black/80 border border-zinc-800 p-2 rounded-lg flex flex-col gap-2 shadow-lg backdrop-blur-sm">
                           <button onClick={handleInitiateMindMap} disabled={isGeneratingMap} className={`p-2 rounded transition-colors ${isGeneratingMap ? 'bg-zinc-800 text-zinc-600' : 'bg-[#00f3ff]/10 text-[#00f3ff] hover:bg-[#00f3ff] hover:text-black'}`}>
                                {isGeneratingMap ? <Loader2 size={18} className="animate-spin" /> : hasInitiatedMap ? <RefreshCw size={18} /> : <Zap size={18} />}
                           </button>
                           <hr className="border-zinc-800" />
                           <button onClick={() => setMapZoom(z => Math.min(z + 0.1, 2))} className="p-2 hover:bg-zinc-800 text-zinc-400 hover:text-white rounded"><ZoomIn size={18} /></button>
                           <button onClick={() => setMapZoom(z => Math.max(z - 0.1, 0.2))} className="p-2 hover:bg-zinc-800 text-zinc-400 hover:text-white rounded"><ZoomOut size={18} /></button>
                       </div>
                   </div>

                   {/* Map Canvas */}
                   <div 
                        className="w-full h-full flex items-center justify-center transition-transform duration-75 origin-center cursor-move"
                        style={{ transform: `scale(${mapZoom}) translate(${pan.x}px, ${pan.y}px)` }}
                   >
                        {isGeneratingMap ? (
                            <Loader text="Structuring Neural Network..." />
                        ) : mindMapData ? (
                            <div className="min-w-max p-20 flex flex-col items-center">
                                {renderMindMapNode(mindMapData, 0, 0, 0)}
                            </div>
                        ) : (
                            <div className="flex flex-col items-center gap-4 text-zinc-700 select-none">
                                <Network size={64} className="opacity-20" />
                                <div className="text-center">
                                    <p className="font-tech text-lg font-bold">NEURAL_MAP_OFFLINE</p>
                                    <p className="font-mono text-xs mt-2">Initialize generation to structure your notes</p>
                                </div>
                            </div>
                        )}
                   </div>
               </div>
           ) : (
               <div className="h-full overflow-y-auto custom-scrollbar p-6">
                   {filteredItems.length === 0 ? (
                       <div className="flex flex-col items-center justify-center h-full text-zinc-600 gap-4 opacity-50">
                           <NotebookIcon size={48} />
                           <p className="font-mono text-xs">NO_ENTRIES_FOUND</p>
                       </div>
                   ) : (
                       <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                           {filteredItems.map(item => (
                               <div key={item.id} className="bg-zinc-900/50 border border-zinc-800/50 hover:border-[#00f3ff]/50 p-5 rounded-lg transition-all duration-300 group hover:shadow-[0_0_15px_rgba(0,243,255,0.05)] flex flex-col relative animate-fade-in-up">
                                   <div className="flex justify-between items-start mb-3">
                                       <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider border ${
                                           item.type === 'word' ? 'bg-emerald-950/30 text-emerald-400 border-emerald-900' :
                                           item.type === 'phrase' ? 'bg-amber-950/30 text-amber-400 border-amber-900' :
                                           'bg-indigo-950/30 text-indigo-400 border-indigo-900'
                                       }`}>
                                           {item.type}
                                       </span>
                                       <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                           <button onClick={() => playPronunciation(item.id, item.text)} className={`p-1.5 rounded-sm bg-black hover:text-[#00f3ff] transition-colors ${playingId === item.id ? 'text-[#00f3ff] animate-pulse' : 'text-zinc-500'}`}><Volume2 size={14} /></button>
                                           <button onClick={() => generateStickyNote(item)} className="p-1.5 rounded-sm bg-black text-zinc-500 hover:text-[#00f3ff] transition-colors"><ImageDown size={14} /></button>
                                           <button onClick={() => onDelete(item.id)} className="p-1.5 rounded-sm bg-black text-zinc-500 hover:text-rose-500 transition-colors"><Trash2 size={14} /></button>
                                       </div>
                                   </div>

                                   <div className="mb-4 flex-1">
                                       <p className="text-lg font-bold text-zinc-100 leading-snug font-serif mb-2">
                                           {item.text}
                                       </p>
                                       {item.definition ? (
                                           <div className="pl-3 border-l-2 border-zinc-800 text-sm text-zinc-400 italic">
                                               {item.definition}
                                           </div>
                                       ) : (
                                           <div className="text-xs text-zinc-600 flex items-center gap-2 animate-pulse">
                                               <Loader2 size={10} className="animate-spin" /> Fetching definition...
                                           </div>
                                       )}
                                   </div>

                                   {/* Context Footer */}
                                   <div className="pt-3 border-t border-zinc-800/50 flex flex-col gap-2">
                                        <div className="flex items-center justify-between text-[10px] text-zinc-500 font-mono">
                                            <span className="flex items-center gap-1"><Clock size={10} /> {new Date(item.timestamp).toLocaleDateString()}</span>
                                            {item.sourceChapter && <span className="truncate max-w-[100px]" title={item.sourceChapter}>{item.sourceChapter}</span>}
                                        </div>
                                        {/* User Comment Input */}
                                        <div className="relative">
                                            <input 
                                                type="text" 
                                                placeholder="Add personal note..." 
                                                defaultValue={item.comment}
                                                onBlur={(e) => onUpdateComment(item.id, e.target.value)}
                                                className="w-full bg-black/30 border border-zinc-800 rounded px-2 py-1 text-xs text-zinc-300 focus:border-[#00f3ff] outline-none placeholder:text-zinc-700"
                                            />
                                        </div>
                                   </div>
                               </div>
                           ))}
                       </div>
                   )}
               </div>
           )}
       </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { NotebookItem, AppSettings, Chapter, MindMapNode } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, Settings2, Type, Loader2, ArrowUpDown, Network, Download, FileText, Share2, ZoomIn, ZoomOut, RefreshCw, Zap, X, Notebook as NotebookIcon, Play, Square, ChevronRight, ChevronDown, Minus, Plus, LogOut, FileDown } from 'lucide-react';
import { generateSpeech, generateMindMapStructure } from '../services/gemini';
import JSZip from 'jszip';
import { Document, Packer, Paragraph, TextRun, HeadingLevel } from 'docx';
import jsPDF from 'jspdf';
import { Loader } from './ui/Loader';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  onBatchUpdateDefinitions?: (updates: Record<string, string>) => void;
  settings: AppSettings;
  activeChapter?: Chapter | null;
  bookTitle?: string;
}

type FilterType = 'all' | 'word' | 'phrase' | 'sentence';
type SortOrder = 'newest' | 'oldest' | 'az' | 'za';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, onBatchUpdateDefinitions, settings, activeChapter, bookTitle }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('all');
  const [sortOrder, setSortOrder] = useState<SortOrder>('newest');

  // Mind Map State
  const [isMindMapMode, setIsMindMapMode] = useState(false);
  const [mindMapData, setMindMapData] = useState<MindMapNode | null>(null);
  const [isGeneratingMap, setIsGeneratingMap] = useState(false);
  const [hasInitiatedMap, setHasInitiatedMap] = useState(false);
  const [collapsedNodeIds, setCollapsedNodeIds] = useState<Set<string>>(new Set());
  const [mapZoom, setMapZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isPanning, setIsPanning] = useState(false);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const lastMousePos = useRef({ x: 0, y: 0 });
  const abortMapRef = useRef<boolean>(false);

  const filteredItems = useMemo(() => {
      let result = activeFilter === 'all' 
        ? [...items] 
        : items.filter(item => item.type === activeFilter);

      switch (sortOrder) {
          case 'newest':
              result.sort((a, b) => b.timestamp - a.timestamp);
              break;
          case 'oldest':
              result.sort((a, b) => a.timestamp - b.timestamp);
              break;
          case 'az':
              result.sort((a, b) => a.text.localeCompare(b.text));
              break;
          case 'za':
              result.sort((a, b) => b.text.localeCompare(a.text));
              break;
      }
      return result;
  }, [items, activeFilter, sortOrder]);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      if (item.comment) {
          ctx.fillStyle = '#f59e0b'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> USER_ANNOTATION:", margin, y); y += 20;
          ctx.fillStyle = '#b45309'; ctx.font = 'italic 14px "Courier New", monospace';
          const commentWords = item.comment.split(' ');
          let commentLine = '';
          for(let n = 0; n < commentWords.length; n++) {
            const testLine = commentLine + commentWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(commentLine, margin, y); commentLine = commentWords[n] + ' '; y += 18;
            } else { commentLine = testLine; }
         }
         ctx.fillText(commentLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const handleInitiateMindMap = async () => {
    if (isGeneratingMap) {
        abortMapRef.current = true;
        setIsGeneratingMap(false);
        return;
    }
    setIsGeneratingMap(true);
    setHasInitiatedMap(true);
    setMapZoom(1);
    setPan({ x: 0, y: 0 });
    setCollapsedNodeIds(new Set());
    abortMapRef.current = false;
    try {
        const title = activeChapter?.title || bookTitle || "Untitled Chapter";
        const context = activeChapter ? `Current Chapter: ${activeChapter.title}` : undefined;
        const structure = await generateMindMapStructure(filteredItems, title, context);
        if (abortMapRef.current) return;
        setMindMapData(structure);
        setIsMindMapMode(true);
    } catch (e) {
        if (!abortMapRef.current) console.error("Failed to generate mind map:", e);
    } finally {
        if (!abortMapRef.current) setIsGeneratingMap(false);
    }
  };

  const toggleNodeCollapse = (id: string, e?: React.MouseEvent) => {
      if (e) e.stopPropagation();
      setCollapsedNodeIds(prev => {
          const next = new Set(prev);
          if (next.has(id)) next.delete(id);
          else next.add(id);
          return next;
      });
  };

  // Panning Handlers
  const handleMapMouseDown = (e: React.MouseEvent) => {
    if (e.button !== 0) return; // Only left click
    setIsPanning(true);
    lastMousePos.current = { x: e.clientX, y: e.clientY };
  };

  const handleMapMouseMove = (e: React.MouseEvent) => {
    if (!isPanning) return;
    const dx = e.clientX - lastMousePos.current.x;
    const dy = e.clientY - lastMousePos.current.y;
    setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
    lastMousePos.current = { x: e.clientX, y: e.clientY };
  };

  const handleMapMouseUp = () => {
    setIsPanning(false);
  };

  // --- Export Functions ---

  const exportToDocx = async () => {
    if (!mindMapData) return;

    const childrenToParagraphs = (node: MindMapNode, level: number): Paragraph[] => {
        const paras = [
             new Paragraph({
                text: node.label,
                heading: level === 0 ? HeadingLevel.TITLE : level === 1 ? HeadingLevel.HEADING_1 : level === 2 ? HeadingLevel.HEADING_2 : undefined,
                bullet: level > 2 ? { level: 0 } : undefined,
             })
        ];
        if (node.children) {
            node.children.forEach(child => {
                paras.push(...childrenToParagraphs(child, level + 1));
            });
        }
        return paras;
    };

    const doc = new Document({
        sections: [{
            properties: {},
            children: childrenToParagraphs(mindMapData, 0),
        }],
    });

    const blob = await Packer.toBlob(doc);
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.docx`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToXmind = async () => {
    if (!mindMapData) return;

    const zip = new JSZip();
    const mapNodeToTopic = (node: MindMapNode): any => {
        const topic: any = {
            "id": node.id,
            "title": node.label,
            "structureClass": "org.xmind.ui.map.unbalanced"
        };
        if (node.children && node.children.length > 0) {
            topic["children"] = {
                "attached": node.children.map(mapNodeToTopic)
            };
        }
        return topic;
    };

    const content = [
        {
            "id": "sheet-1",
            "class": "sheet",
            "title": "Sheet 1",
            "rootTopic": mapNodeToTopic(mindMapData)
        }
    ];

    zip.file("content.json", JSON.stringify(content));
    zip.file("manifest.json", JSON.stringify({
        "file-entries": { "content.json": {}, "metadata.json": {} }
    }));
    zip.file("metadata.json", "{}");

    const blob = await zip.generateAsync({ type: "blob" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.xmind`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToPDF = () => {
      const doc = new jsPDF();
      doc.setFont("helvetica", "bold");
      doc.setFontSize(20);
      doc.text("Notebook Export", 10, 15);

      doc.setFont("helvetica", "normal");
      doc.setFontSize(10);
      doc.text(`Generated: ${new Date().toLocaleString()}`, 10, 22);

      let y = 35;
      const lineHeight = 7;

      filteredItems.forEach((item, idx) => {
          if (y > 270) { doc.addPage(); y = 20; }

          doc.setFont("helvetica", "bold");
          doc.setFontSize(11);
          const typeLabel = `[${item.type.toUpperCase()}]`;
          doc.text(typeLabel, 10, y);

          const textPreview = item.text.length > 50 ? item.text.substring(0, 50) + "..." : item.text;
          doc.text(`"${textPreview}"`, 40, y);

          y += lineHeight;

          if (item.definition) {
             doc.setFont("helvetica", "italic");
             doc.setFontSize(10);
             const defLines = doc.splitTextToSize(`Def: ${item.definition}`, 180);
             doc.text(defLines, 15, y);
             y += (defLines.length * lineHeight) + 2;
          }

          y += 5;
          doc.setDrawColor(200);
          doc.line(10, y, 200, y);
          y += 10;
      });

      doc.save(`notebook-export-${Date.now()}.pdf`);
  };

  const renderMindMapNode = (node: MindMapNode, depth: number = 0, x: number, y: number): React.ReactElement => {
      // Simplified Mind Map rendering: Vertical lists with indentation for now to ensure robustness without complex d3 layout
      // For a true node-link diagram, one would use d3-hierarchy. Here we use a nested recursive layout component.
      return (
          <div key={node.id} className="flex flex-col items-center">
              <div 
                className={`
                    relative p-3 rounded-lg border-2 shadow-lg transition-all duration-300 group
                    ${node.type === 'root' ? 'bg-[#00f3ff]/20 border-[#00f3ff] text-white min-w-[150px] text-center' : ''}
                    ${node.type === 'category' ? 'bg-zinc-900 border-zinc-700 hover:border-zinc-500 text-zinc-200' : ''}
                    ${node.type === 'item' ? 'bg-[#0a0a0c] border-zinc-800 hover:border-[#ff003c] text-zinc-400 max-w-xs text-sm' : ''}
                `}
                onClick={(e) => toggleNodeCollapse(node.id, e)}
              >
                  <div className="font-bold font-mono text-sm flex items-center gap-2">
                     {node.type === 'root' && <Book size={16} />}
                     {node.type === 'category' && <Network size={14} className="text-[#00f3ff]" />}
                     {node.type === 'item' && <FileText size={12} className="text-[#ff003c]" />}
                     {node.label}
                  </div>
                  {node.children && node.children.length > 0 && (
                      <div className="absolute -bottom-3 left-1/2 -translate-x-1/2 bg-zinc-800 rounded-full p-0.5 border border-zinc-700">
                          {collapsedNodeIds.has(node.id) ? <Plus size={10} /> : <Minus size={10} />}
                      </div>
                  )}
              </div>

              {!collapsedNodeIds.has(node.id) && node.children && node.children.length > 0 && (
                  <div className="flex items-start gap-8 mt-8 border-t border-zinc-700/50 pt-8 relative">
                      {/* Connector lines logic would go here in a canvas or SVG, using simple CSS borders for tree structure */}
                      {node.children.map((child, idx) => (
                          <div key={child.id} className="relative">
                              {renderMindMapNode(child, depth + 1, 0, 0)}
                          </div>
                      ))}
                  </div>
              )}
          </div>
      );
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left overflow-hidden" style={fontStyle}>
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 animate-fade-in shadow-[0_0_15px_rgba(0,243,255,0.05)] flex-nowrap gap-2 z-10">
          <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
             <NotebookIcon size={18} className="text-[#00f3ff]" />
             <span>Mem_Log</span>
          </div>

          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                  <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                  <select value={activeFilter} onChange={(e) => setActiveFilter(e.target.value as FilterType)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[90px] bg-[#050505]">
                      <option value="all">ALL_DATA</option>
                      <option value="word">TERMS</option>
                      <option value="phrase">PHRASES</option>
                      <option value="sentence">IDEAS</option>
                  </select>
                  <div className="w-[1px] h-4 bg-zinc-700"></div>
                   <div className="p-1.5 text-zinc-500"><ArrowUpDown size={16} /></div>
                   <select value={sortOrder} onChange={(e) => setSortOrder(e.target.value as SortOrder)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[90px] bg-[#050505]">
                      <option value="newest">LATEST</option>
                      <option value="oldest">OLDEST</option>
                      <option value="az">A-Z</option>
                      <option value="za">Z-A</option>
                   </select>
              </div>

              <div className="flex items-center gap-2">
                 <button onClick={() => setIsMindMapMode(!isMindMapMode)} className={`flex items-center gap-2 px-3 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all ${isMindMapMode ? 'bg-[#00f3ff] text-black' : 'bg-zinc-900 text-zinc-400 hover:text-white'}`}>
                     <Network size={14} /> {isMindMapMode ? 'GRID_VIEW' : 'MIND_MAP'}
                 </button>

                 {isMindMapMode && mindMapData && (
                     <div className="flex items-center gap-1 bg-black/50 p-1 rounded-sm border border-zinc-800">
                         <button onClick={exportToDocx} className="p-1.5 hover:bg-zinc-800 text-zinc-400 hover:text-[#00f3ff] transition-colors" title="Export DOCX"><FileText size={14} /></button>
                         <button onClick={exportToXmind} className="p-1.5 hover:bg-zinc-800 text-zinc-400 hover:text-[#00f3ff] transition-colors" title="Export XMIND"><Share2 size={14} /></button>
                         <button onClick={exportToPDF} className="p-1.5 hover:bg-zinc-800 text-zinc-400 hover:text-[#00f3ff] transition-colors" title="Export PDF"><FileDown size={14} /></button>
                     </div>
                 )}
              </div>
          </div>
       </div>

       <div className="flex-1 min-h-0 bg-[#0a0a0c] border border-zinc-800 rounded-lg overflow-hidden relative shadow-inner">
           {isMindMapMode ? (
               <div className="w-full h-full relative overflow-hidden bg-[#050505]" ref={mapContainerRef} onMouseDown={handleMapMouseDown} onMouseMove={handleMapMouseMove} onMouseUp={handleMapMouseUp} onMouseLeave={handleMapMouseUp}>
                   {/* Mind Map Controls Overlay */}
                   <div className="absolute top-4 left-4 z-20 flex flex-col gap-2">
                       <div className="bg-black/80 border border-zinc-800 p-2 rounded-lg flex flex-col gap-2 shadow-lg backdrop-blur-sm">
                           <button onClick={handleInitiateMindMap} disabled={isGeneratingMap} className={`p-2 rounded transition-colors ${isGeneratingMap ? 'bg-zinc-800 text-zinc-600' : 'bg-[#00f3ff]/10 text-[#00f3ff] hover:bg-[#00f3ff] hover:text-black'}`}>
                                {isGeneratingMap ? <Loader2 size={18} className="animate-spin" /> : hasInitiatedMap ? <RefreshCw size={18} /> : <Zap size={18} />}
                           </button>
                           <hr className="border-zinc-800" />
                           <button onClick={() => setMapZoom(z => Math.min(z + 0.1, 2))} className="p-2 hover:bg-zinc-800 text-zinc-400 hover:text-white rounded"><ZoomIn size={18} /></button>
                           <button onClick={() => setMapZoom(z => Math.max(z - 0.1, 0.2))} className="p-2 hover:bg-zinc-800 text-zinc-400 hover:text-white rounded"><ZoomOut size={18} /></button>
                       </div>
                   </div>

                   {/* Map Canvas */}
                   <div 
                        className="w-full h-full flex items-center justify-center transition-transform duration-75 origin-center cursor-move"
                        style={{ transform: `scale(${mapZoom}) translate(${pan.x}px, ${pan.y}px)` }}
                   >
                        {isGeneratingMap ? (
                            <Loader text="Structuring Neural Network..." />
                        ) : mindMapData ? (
                            <div className="min-w-max p-20 flex flex-col items-center">
                                {renderMindMapNode(mindMapData, 0, 0, 0)}
                            </div>
                        ) : (
                            <div className="flex flex-col items-center gap-4 text-zinc-700 select-none">
                                <Network size={64} className="opacity-20" />
                                <div className="text-center">
                                    <p className="font-tech text-lg font-bold">NEURAL_MAP_OFFLINE</p>
                                    <p className="font-mono text-xs mt-2">Initialize generation to structure your notes</p>
                                </div>
                            </div>
                        )}
                   </div>
               </div>
           ) : (
               <div className="h-full overflow-y-auto custom-scrollbar p-6">
                   {filteredItems.length === 0 ? (
                       <div className="flex flex-col items-center justify-center h-full text-zinc-600 gap-4 opacity-50">
                           <NotebookIcon size={48} />
                           <p className="font-mono text-xs">NO_ENTRIES_FOUND</p>
                       </div>
                   ) : (
                       <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                           {filteredItems.map(item => (
                               <div key={item.id} className="bg-zinc-900/50 border border-zinc-800/50 hover:border-[#00f3ff]/50 p-5 rounded-lg transition-all duration-300 group hover:shadow-[0_0_15px_rgba(0,243,255,0.05)] flex flex-col relative animate-fade-in-up">
                                   <div className="flex justify-between items-start mb-3">
                                       <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider border ${
                                           item.type === 'word' ? 'bg-emerald-950/30 text-emerald-400 border-emerald-900' :
                                           item.type === 'phrase' ? 'bg-amber-950/30 text-amber-400 border-amber-900' :
                                           'bg-indigo-950/30 text-indigo-400 border-indigo-900'
                                       }`}>
                                           {item.type}
                                       </span>
                                       <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                           <button onClick={() => playPronunciation(item.id, item.text)} className={`p-1.5 rounded-sm bg-black hover:text-[#00f3ff] transition-colors ${playingId === item.id ? 'text-[#00f3ff] animate-pulse' : 'text-zinc-500'}`}><Volume2 size={14} /></button>
                                           <button onClick={() => generateStickyNote(item)} className="p-1.5 rounded-sm bg-black text-zinc-500 hover:text-[#00f3ff] transition-colors"><ImageDown size={14} /></button>
                                           <button onClick={() => onDelete(item.id)} className="p-1.5 rounded-sm bg-black text-zinc-500 hover:text-rose-500 transition-colors"><Trash2 size={14} /></button>
                                       </div>
                                   </div>

                                   <div className="mb-4 flex-1">
                                       <p className="text-lg font-bold text-zinc-100 leading-snug font-serif mb-2">
                                           {item.text}
                                       </p>
                                       {item.definition ? (
                                           <div className="pl-3 border-l-2 border-zinc-800 text-sm text-zinc-400 italic">
                                               {item.definition}
                                           </div>
                                       ) : (
                                           <div className="text-xs text-zinc-600 flex items-center gap-2 animate-pulse">
                                               <Loader2 size={10} className="animate-spin" /> Fetching definition...
                                           </div>
                                       )}
                                   </div>

                                   {/* Context Footer */}
                                   <div className="pt-3 border-t border-zinc-800/50 flex flex-col gap-2">
                                        <div className="flex items-center justify-between text-[10px] text-zinc-500 font-mono">
                                            <span className="flex items-center gap-1"><Clock size={10} /> {new Date(item.timestamp).toLocaleDateString()}</span>
                                            {item.sourceChapter && <span className="truncate max-w-[100px]" title={item.sourceChapter}>{item.sourceChapter}</span>}
                                        </div>
                                        {/* User Comment Input */}
                                        <div className="relative">
                                            <input 
                                                type="text" 
                                                placeholder="Add personal note..." 
                                                defaultValue={item.comment}
                                                onBlur={(e) => onUpdateComment(item.id, e.target.value)}
                                                className="w-full bg-black/30 border border-zinc-800 rounded px-2 py-1 text-xs text-zinc-300 focus:border-[#00f3ff] outline-none placeholder:text-zinc-700"
                                            />
                                        </div>
                                   </div>
                               </div>
                           ))}
                       </div>
                   )}
               </div>
           )}
       </div>
    </div>
  );
};
